class Solution:
    def longestAlternating(self, nums):
        # Independent formulation: for every choice of which single index to delete
        # (including deleting nothing), build the resulting array directly and scan
        # it for the longest alternating contiguous run. Structurally different from
        # the rolling-state DP used in the optimal solution below.
        def longest_alt_run(arr):
            if not arr:
                return 0
            best = 1
            cur = 1
            prev_dir = None
            for i in range(1, len(arr)):
                if arr[i] == arr[i - 1]:
                    cur = 1
                    prev_dir = None
                else:
                    d = arr[i] > arr[i - 1]
                    if prev_dir is None or d != prev_dir:
                        cur += 1
                    else:
                        cur = 2
                    prev_dir = d
                best = max(best, cur)
            return best

        n = len(nums)
        best = longest_alt_run(nums)
        for d in range(n):
            modified = nums[:d] + nums[d + 1:]
            best = max(best, longest_alt_run(modified))
        return best

