class Solution:
    def longestAlternating(self, nums: List[int]) -> int:
        n = len(nums)
        up0 = [1] * n
        down0 = [1] * n
        up1 = [1] * n
        down1 = [1] * n
        for i in range(1, n):
            if nums[i] > nums[i - 1]:
                up0[i] = max(up0[i], down0[i - 1] + 1)
                up1[i] = max(up1[i], down1[i - 1] + 1)
            elif nums[i] < nums[i - 1]:
                down0[i] = max(down0[i], up0[i - 1] + 1)
                down1[i] = max(down1[i], up1[i - 1] + 1)
            if i >= 2:
                if nums[i] > nums[i - 2]:
                    up1[i] = max(up1[i], down0[i - 2] + 1)
                if nums[i] < nums[i - 2]:
                    down1[i] = max(down1[i], up0[i - 2] + 1)
        ans = 1
        for i in range(n):
            ans = max(ans, up0[i], down0[i], up1[i], down1[i])
        return ans

