var longestAlternating = function(nums) {
    const n = nums.length;
    const up0 = new Array(n).fill(1);
    const down0 = new Array(n).fill(1);
    const up1 = new Array(n).fill(1);
    const down1 = new Array(n).fill(1);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            up0[i] = Math.max(up0[i], down0[i - 1] + 1);
            up1[i] = Math.max(up1[i], down1[i - 1] + 1);
        } else if (nums[i] < nums[i - 1]) {
            down0[i] = Math.max(down0[i], up0[i - 1] + 1);
            down1[i] = Math.max(down1[i], up1[i - 1] + 1);
        }
        if (i >= 2) {
            if (nums[i] > nums[i - 2]) {
                up1[i] = Math.max(up1[i], down0[i - 2] + 1);
            }
            if (nums[i] < nums[i - 2]) {
                down1[i] = Math.max(down1[i], up0[i - 2] + 1);
            }
        }
    }
    let ans = 1;
    for (let i = 0; i < n; i++) {
        ans = Math.max(ans, up0[i], down0[i], up1[i], down1[i]);
    }
    return ans;
};
